/* Test driver */
public class Main {
    public static void main(String[] args) {
        Logger.resetAll();
        FileAppender fa = new FileAppender("test.log");
        LoggerConfig cfg = new LoggerConfig().setLevel(LogLevel.WARN).setFormatter(new SimpleFormatter()).addAppender(fa);
        Logger lg = Logger.getLogger("X");
        lg.setConfig(cfg);
        lg.debug("d"); lg.info("i"); lg.warn("w"); lg.error("e");
        System.out.println(fa.getLineCount() == 2 ? "FILTER_OK" : "FILTER_FAIL");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        Logger.resetAll();
        FileAppender fa = new FileAppender("a.log");
        AsyncAppender async = new AsyncAppender(fa, 3);
        LoggerConfig cfg = new LoggerConfig().setLevel(LogLevel.DEBUG).setFormatter(new SimpleFormatter()).addAppender(async);
        Logger lg = Logger.getLogger("Y");
        lg.setConfig(cfg);
        lg.info("m1"); lg.info("m2");
        int beforeFlush = fa.getLineCount();
        lg.info("m3");
        int afterFlush = fa.getLineCount();
        System.out.println((beforeFlush == 0 && afterFlush == 3) ? "ASYNC_OK" : "ASYNC_FAIL");
    }
}
